let items = document.querySelectorAll('[class*="card"], [class*="skill"], h3, [class*="heading"]');
let results = [];
items.forEach(el => {
  let text = el.textContent.toLowerCase();
  if (text.includes('web') || text.includes('ui') || text.includes('dashboard') || text.includes('chat') || text.includes('webui') || text.includes('frontend')) {
    results.push(el.textContent.trim().substring(0, 100));
  }
});
